            vQueryId = "retrieveWrkPlInfo2";
            pWhere = ",,T";
            break;
        default:
            pWhere = ",LOGISCLNT1";	//거래처삭제여부가0 이고 물류거래처인 경우만
            break;
    };

    switch (div) {
        //자가운송사(저장용) : udc따로 처리
        case 2:
            scwin.objArray = [div, "ed_selfTransClntNo", "ed_selfTransClntNm", "ed_selfTransClntTelNo", "ed_selfTransClntMpNo", "ed_selfTransPicEmpNm"];
            break;
        //요청거래처(저장용)        거래처코드[1]   거래처명[2]  사업자번호[3] 담당자명[4]      연락처[5]
        case 3:
            scwin.objArray = [div, "ed_reqClntNo", "tbx_reqClntNm", "ed_reqCrn", "ed_reqPicEmpNm", "ed_reqClntTelNo"];
            $c.gus.cfDisableObjects([ed_reqCrn, ed_bilgCrn, ed_realMchtCrn]);
            break;
        //청구거래처(저장용)
        case 4:
            scwin.objArray = [div, "ed_bilgClntNo", "tbx_bilgClntNm", "ed_bilgCrn", "ed_bilgPicEmpNm", "ed_bilgClntTelNo"];
            $c.gus.cfDisableObjects([ed_reqCrn, ed_bilgCrn, ed_realMchtCrn]);
            break;
        //실화주거래처(저장용)
        case 5:
            scwin.objArray = [div, "ed_realMchtClntNo", "tbx_realMchtClntNm", "ed_realMchtCrn", "ed_realMchtPicEmpNm", "ed_realMchtClntTelNo"];
            $c.gus.cfDisableObjects([ed_reqCrn, ed_bilgCrn, ed_realMchtCrn]);
            break;
        case 6:
            return;
        default:
            break;
    };

    //param1값 없을 시 값 빈값 처리
    if($c.gus.cfIsNull(param1)) {
        for(let i=0; i<obj.length; i++) {
            let objId  = obj[i];
            let objVal = $p.getComponentById(objId);
            objVal.setValue("");
        }
    }
    //UDC 호출
    switch (div) {
        case 1:
            udc_srchSelfTransClntNo.cfCommonPopUp(scwin.udc_srchSelfTransClntNo_callBackFunc, param1, param2, pWinCloseTF, null
                                    , null, null, null, pWhere, null
                                    , null, null, null, null, null
                                    , null, null
            );    
            break;
        case 2:
            udc_selfTransClntNo.cfCommonPopUp(scwin.udc_selfTransClntNo_callBackFunc, param1, param2, pWinCloseTF, null
                                    , null, null, null, pWhere, null
                                    , null, null, null, null, "F"
                                    , null, null
            );
            break;
        case 3:
        case 4:
        case 5:
        //case 6:
            udc_comCode.setSelectId(vQueryId);
            //조회조건 9번째, 전체검색허용여부 15번째
            udc_comCode.cfCommonPopUp(
                scwin.udc_comCode_callBackFunc
                , param1
                , param2
                , pWinCloseTF
                , null
                , null
                , null
                , null
                , pWhere
                , null
                , null
                , null
                , null
                , null
                , "F"
                , null);
            break
        default:
            break;
    };
};

